mapper.update:

update td_plan_result set enabled_flag = 0
where plan_id      = #{planId,jdbcType=BIGINT} and enabled_flag = 1
and check_method = #{checkMethod, jdbcType = VARCHAR}

mapper.select:
SELECT temp.name AS name, temp.work_card AS work_card, temp.pe_id AS pe_id, temp.duration AS sum_duration, temp.participate_num AS participate_num, ( SELECT fdt.dept_name FROM fnd_dept fdt WHERE fd.ext_dept_id = fdt.id ) AS dept_name, ( SELECT fdt.dept_name FROM fnd_dept fdt WHERE fd.ext_department_id = fdt.id ) AS department, ( SELECT fdt.dept_name FROM fnd_dept fdt WHERE fd.ext_team_id = fdt.id ) AS team, tpr.duration AS duration, tpr.grade AS grade, tpr.evaluate AS evaluate, tp.training_name AS training_name, tp.training_method AS training_method, tp.training_content AS training_content, tpi.begin_date AS begin_date, tpi.end_date AS end_date, tpi.training_address AS training_address, tpi.training_time_quantity AS training_time_quantity, CASE
WHEN isnull( tpi.out_teacher, '' ) = '' THEN ( SELECT STUFF(( SELECT ',' + pe.name FROM pm_employee pe JOIN td_plan_employee tpe ON pe.id = tpe.employee_id AND tpe.plan_implement_id = tpi.id AND tpe.enabled_flag = 1 AND tpe.type = 'teacher' WHERE pe.enabled_flag = 1 FOR XML PATH ( '' )), 1, 1, '' ) ) ELSE ( SELECT tpi.out_teacher + STUFF(( SELECT ',' + pe.name FROM pm_employee pe JOIN td_plan_employee tpe ON pe.id = tpe.employee_id AND tpe.plan_implement_id = tpi.id AND tpe.enabled_flag = 1 AND tpe.type = 'teacher' WHERE pe.enabled_flag = 1 FOR XML PATH ( '' )), 1, 1, '' ) ) END AS teacher FROM ( SELECT pe.name, pe.work_card, pe.id AS pe_id, sum ( tpr.duration ) AS duration, COUNT ( tpr.employee_id ) AS participate_num FROM td_plan tp JOIN td_plan_implement tpi ON tp.id = tpi.plan_id AND tp.enabled_flag = 1 AND tp.show_flag = 1 and tp.safety_training_flag = 0 AND tpi.enabled_flag = 1 AND tpi.approval_status = '已完成' JOIN td_plan_employee tpe ON tpe.plan_implement_id = tpi.id AND tpe.type = 'employee' AND tpe.enabled_flag = 1 JOIN pm_employee pe ON pe.id = tpe.employee_id AND pe.enabled_flag = 1 LEFT JOIN td_plan_result tpr ON tpr.plan_id = tp.id AND tpr.employee_id = tpe.employee_id WHERE tpr.enabled_flag = 1
AND tpi.begin_date BETWEEN #{beginDate, jdbcType = DATE} AND #{endDate, jdbcType = DATE} AND tpi.end_date BETWEEN #{beginDate, jdbcType = DATE} AND #{endDate, jdbcType = DATE}
GROUP BY pe.name, pe.work_card, pe.id ) temp JOIN pm_employee_job pej ON pej.employee_id = temp.pe_id AND pej.enabled_flag = 1 AND pej.job_main_flag = 1 JOIN fnd_dept fd ON fd.id = pej.dept_id AND fd.deleted_flag = 0 LEFT JOIN td_plan_result tpr ON tpr.employee_id = temp.pe_id JOIN td_plan tp ON tpr.plan_id = tp.id AND tp.enabled_flag = 1 AND tp.show_flag = 1 and tp.safety_training_flag = 0 JOIN td_plan_implement tpi ON tp.id = tpi.plan_id AND tpi.enabled_flag = 1 AND tpi.approval_status = '已完成' WHERE tpr.enabled_flag = 1
AND tpi.begin_date BETWEEN #{beginDate, jdbcType = DATE} AND #{endDate, jdbcType = DATE} AND tpi.end_date BETWEEN #{beginDate, jdbcType = DATE} AND #{endDate, jdbcType = DATE}
order by tp.id, temp.work_card

select tpa.id, tp.training_name as training_name, tpi.training_address as training_address, tpi.training_time_quantity as training_time_quantity, tpi.begin_date as begin_date, tpi.end_date as end_date, tp.plan_money as plan_money, tpi.training_money as training_money, pe.name as name , pe.work_card as work_card, pe.id_number as id_number, tpa.service_year as service_year, tpa.begin_date as service_begin_date, tpa.end_date as service_end_date
from td_plan tp JOIN td_plan_implement tpi ON tp.id = tpi.plan_id AND tp.enabled_flag = 1 AND tp.show_flag = 1 and tp.safety_training_flag = 0 AND tpi.enabled_flag = 1 AND tpi.approval_status = '已完成' join td_plan_result tpr on tpr.plan_id = tp.id and tpr.enabled_flag = 1 and tpr.need_flag = 1 join pm_employee pe on tpr.employee_id = pe.id and pe.enabled_flag = 1 join td_plan_agreement tpa on tpa.plan_id = tpr.plan_id and tpa.enabled_flag = 1 and tpa.employee_id = pe.id where 1 = 1
AND tpi.begin_date BETWEEN #{beginDate, jdbcType = DATE} AND #{endDate, jdbcType = DATE} AND tpi.end_date BETWEEN #{beginDate, jdbcType = DATE} AND #{endDate, jdbcType = DATE}
and tp.id = #{planId, jdbcType = BIGINT}
AND tpa.begin_date BETWEEN #{serviceBeginDate, jdbcType = DATE} AND #{serviceEndDate, jdbcType = DATE} AND tpa.end_date BETWEEN #{serviceBeginDate, jdbcType = DATE} AND #{serviceEndDate, jdbcType = DATE}
and tpr.check_method = #{checkMethod, jdbcType = VARCHAR} and tpa.check_method = #{checkMethod, jdbcType = VARCHAR}
order by tp.id, pe.work_card
